search.query:
`dcso_investigation_rollup`
| eval __seed=0, workflow=mvappend(
    if(deny_count>=2, "Repeated Deny Activity", null()),
    if(dangerous_deny_count>=1, "Dangerous Command Or Tool Denied", null()),
    if(deny_count>=1 AND retry_after_deny_count>=1, "Policy Bypass Or Retry After Denial", null()),
    if(session_stuck_count>=1 OR session_retried_count>=2, "Stuck Or Retry-Storm Session", null()),
    if(runtime_error_count>=2 AND mvfind(risk_rule_ids, "RISK-009")>=0, "Runtime Error Burst Around Risky Run", null()),
    if((max_cost_usd>=1 OR max_duration_ms>=5000) AND (risk_state="risky" OR risk_state="critical"), "High-Cost Or Long-Duration Risky Run", null())
  )
| append [ | makeresults | eval __seed=1, workflow="__none__" ]
| mvexpand workflow
| where __seed=0 AND isnotnull(workflow) AND workflow!="" AND workflow!="__none__"
| eval workflow_order=case(
    workflow="Repeated Deny Activity", 10,
    workflow="Dangerous Command Or Tool Denied", 20,
    workflow="Policy Bypass Or Retry After Denial", 30,
    workflow="Stuck Or Retry-Storm Session", 40,
    workflow="Runtime Error Burst Around Risky Run", 50,
    workflow="High-Cost Or Long-Duration Risky Run", 60,
    1=1, 99
  )
| sort workflow_order - last_seen_epoch
| table workflow run_id session_id risk_state risk_reason deny_count dangerous_deny_count retry_after_deny_count session_retried_count queue_pressure_count session_stuck_count runtime_error_count max_cost_usd max_duration_ms risk_rule_ids last_seen
| head 30
